"use strict";(self.webpackChunkgolioth_developer_training=self.webpackChunkgolioth_developer_training||[]).push([[53],{1109:function(e){e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Developer Training Overview","href":"/docs/intro","docId":"intro"},{"type":"category","label":"Golioth Introduction","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"What is Golioth?","href":"/docs/golioth-intro/what-is-golioth","docId":"golioth-intro/what-is-golioth"},{"type":"link","label":"Training Requirements","href":"/docs/golioth-intro/requirements","docId":"golioth-intro/requirements"},{"type":"link","label":"Console Signup and Exploration","href":"/docs/golioth-intro/signup","docId":"golioth-intro/signup"}]},{"type":"category","label":"CircuitPython Exercises","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"CircuitPython Introduction","href":"/docs/circuitpython-exercises/circuitpython-intro","docId":"circuitpython-exercises/circuitpython-intro"},{"type":"link","label":"CircuitPython Setup","href":"/docs/circuitpython-exercises/circuitpython-setup","docId":"circuitpython-exercises/circuitpython-setup"},{"type":"link","label":"CircuitPython Demo First Steps","href":"/docs/circuitpython-exercises/circuitpython-demo","docId":"circuitpython-exercises/circuitpython-demo"},{"type":"link","label":"Exploring Golioth using the MagTag","href":"/docs/circuitpython-exercises/circuitpython-explore","docId":"circuitpython-exercises/circuitpython-explore"}]},{"type":"category","label":"Zephyr Exercises","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Zephyr Introduction","href":"/docs/zephyr-intro/overview","docId":"zephyr-intro/overview"},{"type":"link","label":"Zephyr Toolchain Installation","href":"/docs/zephyr-intro/toolchain-install","docId":"zephyr-intro/toolchain-install"},{"type":"category","label":"Code Examples","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Blinky Example","href":"/docs/zephyr-intro/zephyr-examples/blinky","docId":"zephyr-intro/zephyr-examples/blinky"},{"type":"link","label":"Golioth Hello Example","href":"/docs/zephyr-intro/zephyr-examples/golioth-hello","docId":"zephyr-intro/zephyr-examples/golioth-hello"},{"type":"link","label":"Golioth Stream Example","href":"/docs/zephyr-intro/zephyr-examples/golioth-stream","docId":"zephyr-intro/zephyr-examples/golioth-stream"},{"type":"link","label":"Golioth Observe Example","href":"/docs/zephyr-intro/zephyr-examples/golioth-observe","docId":"zephyr-intro/zephyr-examples/golioth-observe"}]},{"type":"link","label":"Zephyr Tips and Gotchas","href":"/docs/zephyr-intro/zephyr-tips","docId":"zephyr-intro/zephyr-tips"}]},{"type":"category","label":"Future Exercises","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Returning to CircuitPython","href":"/docs/future-exercises/circuitpython-recover","docId":"future-exercises/circuitpython-recover"},{"type":"link","label":"Device Firmware Updates (OTA)","href":"/docs/future-exercises/dfu","docId":"future-exercises/dfu"},{"type":"link","label":"Data Visualization","href":"/docs/future-exercises/data-visualization","docId":"future-exercises/data-visualization"}]}]},"docs":{"circuitpython-exercises/circuitpython-demo":{"id":"circuitpython-exercises/circuitpython-demo","title":"CircuitPython Demo First Steps","description":"Now that you have code and credentials on your device from the previous step, it\'s time to put this to use. Remember, this stage of the training is to showcase the various ways to send data to the Golioth cloud.","sidebar":"tutorialSidebar"},"circuitpython-exercises/circuitpython-explore":{"id":"circuitpython-exercises/circuitpython-explore","title":"Exploring Golioth using the MagTag","description":"LightDB State vs Stream: A brief overview","sidebar":"tutorialSidebar"},"circuitpython-exercises/circuitpython-intro":{"id":"circuitpython-exercises/circuitpython-intro","title":"CircuitPython Introduction","description":"Overview","sidebar":"tutorialSidebar"},"circuitpython-exercises/circuitpython-setup":{"id":"circuitpython-exercises/circuitpython-setup","title":"CircuitPython Setup","description":"The reason we are interested in CircuitPython is the \\"drag and drop\\" nature of this experience. Below you will install an interpreter, load a library, load code onto your device, and add credentials by dropping files onto a drive and then modifying one of those files.","sidebar":"tutorialSidebar"},"future-exercises/circuitpython-recover":{"id":"future-exercises/circuitpython-recover","title":"Returning to CircuitPython","description":"Overview","sidebar":"tutorialSidebar"},"future-exercises/data-visualization":{"id":"future-exercises/data-visualization","title":"Data Visualization","description":"Overview","sidebar":"tutorialSidebar"},"future-exercises/dfu":{"id":"future-exercises/dfu","title":"Device Firmware Updates (OTA)","description":"Overview","sidebar":"tutorialSidebar"},"golioth-intro/requirements":{"id":"golioth-intro/requirements","title":"Training Requirements","description":"Hardware requirements","sidebar":"tutorialSidebar"},"golioth-intro/signup":{"id":"golioth-intro/signup","title":"Console Signup and Exploration","description":"This section includes references to the Golioth docs site. We are linking you there so you have the most up-to-date directions on getting started with the Golioth Cloud. Once you have completed a section, you will come back to this page for further instructions.","sidebar":"tutorialSidebar"},"golioth-intro/what-is-golioth":{"id":"golioth-intro/what-is-golioth","title":"What is Golioth?","description":"Golioth is a straightforward commercial IoT platform, built for scale. What that means for you, the Developer, is that we want to help get your deployment prototyped quickly and then use that same tooling to be able to expand your application from 1 device to thousands or millions of devices in the field.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Developer Training Overview","description":"What is this training all about?","sidebar":"tutorialSidebar"},"zephyr-intro/overview":{"id":"zephyr-intro/overview","title":"Zephyr Introduction","description":"The Zephyr Tutorial is the main part of the training targeted at beginner to intermediate hardware and firmware users. Zephyr is the most likely development path for an advanced product including an RTOS and highlights many of the best features of Golioth. It also showcases the flexibility of Zephyr: we can target the same hardware that we had previously been using with CircuitPython. This section of the tutorial will include written instructions for getting started with the Zephyr toolchain and compiling early examples. The goal is to get through all examples, but this will be time permitting.","sidebar":"tutorialSidebar"},"zephyr-intro/toolchain-install":{"id":"zephyr-intro/toolchain-install","title":"Zephyr Toolchain Installation","description":"This section includes references to the Golioth docs site. We are linking you there so you have the most up-to-date directions to install the Zephyr toolchain and ESP32 compiler. Once you have completed that section, you will come back to this page for further instructions.","sidebar":"tutorialSidebar"},"zephyr-intro/zephyr-examples/blinky":{"id":"zephyr-intro/zephyr-examples/blinky","title":"Blinky Example","description":"The Blinky example is the most basic application possible&ndash;one blinking LED. It shows that your toolchain is capable of building code correctly, that you are able to flash a binary to the device, and that the device runs the binary as expected.","sidebar":"tutorialSidebar"},"zephyr-intro/zephyr-examples/golioth-hello":{"id":"zephyr-intro/zephyr-examples/golioth-hello","title":"Golioth Hello Example","description":"The Hello example is the most basic network-connected example. It shows not only that you can build and flash a binary, but that the binary includes credentials for your WiFi and the Golioth cloud, and that the board can successfully connect to both.","sidebar":"tutorialSidebar"},"zephyr-intro/zephyr-examples/golioth-observe":{"id":"zephyr-intro/zephyr-examples/golioth-observe","title":"Golioth Observe Example","description":"The Observe example configures the MagTag to watch a LightDB state endpoint on the Golioth servers for changes. When data is updated on the could, the device recognizes this quickly and a callback is executed. For this example, a LightDB State endpoint called leds will monitor a value from 0 to 15 to control the on/off state of the LEDs on the MagTag.","sidebar":"tutorialSidebar"},"zephyr-intro/zephyr-examples/golioth-stream":{"id":"zephyr-intro/zephyr-examples/golioth-stream","title":"Golioth Stream Example","description":"The Stream example sends accelerometer sensor data to the Golioth Cloud every few seconds. Each JSON object receives a timestamp and is stored in a database we refer to as LightDB stream.","sidebar":"tutorialSidebar"},"zephyr-intro/zephyr-tips":{"id":"zephyr-intro/zephyr-tips","title":"Zephyr Tips and Gotchas","description":"Use this page as a reference for reminders and common gotchas.","sidebar":"tutorialSidebar"}}}')}}]);